using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var topic = args.Length > 0 ? string.Join(' ', args) : "recent advances in quantum computing";

Console.WriteLine($"🔬 Research Agent Starting — topic: \"{topic}\"\n");

// --- Tools ---
var researchTools = new ResearchTools();

// --- Build chat client with tool support ---
IChatClient client = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools = [
        AIFunctionFactory.Create(researchTools.SearchWeb),
        AIFunctionFactory.Create(researchTools.TakeNote),
        AIFunctionFactory.Create(researchTools.GetNotes),
    ]
};

// --- Agent loop ---
List<ChatMessage> messages =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to research the given topic thoroughly.

        Strategy:
        1. Search the web multiple times with different queries to gather diverse information.
        2. Take notes on key findings as you go.
        3. After gathering enough information (at least 3 searches), review your notes and
           produce a comprehensive summary with key points and sources.

        Always use the tools available to you. Do not fabricate information.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
];

Console.WriteLine("Agent is researching...\n");

// Let the agent run until it produces a final response without tool calls
var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n═══════════════════════════════════════════");
Console.WriteLine($"\n📝 Notes collected: {researchTools.NoteCount}");
Console.WriteLine($"🔍 Searches performed: {researchTools.SearchCount}");

// --- Tool implementations ---
public class ResearchTools
{
    private readonly List<string> _notes = [];
    public int NoteCount => _notes.Count;
    public int SearchCount { get; private set; }

    [Description("Search the web for information on a query. Returns a list of search result snippets.")]
    public string SearchWeb([Description("The search query")] string query)
    {
        SearchCount++;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        // Simulated web search results — replace with a real search API (e.g., Bing, Brave, SerpAPI)
        var results = SimulateSearchResults(query);
        return results;
    }

    [Description("Save a note about a key finding from the research.")]
    public string TakeNote([Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note saved successfully (total notes: {_notes.Count}).";
    }

    [Description("Retrieve all notes taken so far during research.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n\n", _notes.Select((n, i) => $"[Note {i + 1}]: {n}"));
    }

    private static string SimulateSearchResults(string query)
    {
        // This is a placeholder. In production, call a real search API.
        return $"""
            Search results for "{query}":

            1. [Research Paper] Recent developments show significant progress in this area.
               Key findings include new methodologies and improved performance metrics.
               Source: arxiv.org/papers/2026/{query.GetHashCode():x8}

            2. [News Article] Industry experts report breakthroughs related to "{query}".
               Multiple organizations are investing heavily in related technologies.
               Source: techreview.com/2026/05/{Uri.EscapeDataString(query[..Math.Min(20, query.Length)])}

            3. [Academic Survey] A comprehensive survey covering the state of the art.
               Identifies key challenges and future research directions.
               Source: nature.com/articles/s41586-026-{Math.Abs(query.GetHashCode()) % 10000:D5}
            """;
    }
}

